const funnel = $input.all()[0]?.json || {};
const activity = $input.all()[1]?.json || {};
const msgs = $input.all()[2]?.json || {};
const kpis = $input.all()[3]?.json || {};

const today = new Date().toLocaleDateString('es-AR', {dateStyle:'long'});

const report = `📊 *REPORTE SEMANAL OUTREACH – ${today}*

🔢 *FUNNEL ACTUAL*
├ 🆕 NEW: ${funnel.funnel_new || 0}
├ 📞 CONTACTED: ${funnel.funnel_contacted || 0}
├ 💬 IN_CONVERSATION: ${funnel.funnel_in_conv || 0}
├ ⭐ QUALIFIED: ${funnel.funnel_qualified || 0}
├ 🏗️ ONBOARDING: ${funnel.funnel_onboarding || 0}
├ 🏆 WON: ${funnel.funnel_won || 0}
├ 🥶 COLD: ${funnel.funnel_cold || 0}
├ ❌ LOST: ${funnel.funnel_lost || 0}
└ 🗑️ DISCARDED: ${funnel.funnel_discarded || 0}

📈 *ACTIVIDAD ESTA SEMANA*
├ Contactados: ${activity.contacted_this_week || 0}
├ Conversaciones: ${activity.conversations_this_week || 0}
├ Calificados: ${activity.qualified_this_week || 0}
├ En Onboarding: ${activity.onboarding_this_week || 0}
├ Ganados: ${activity.won_this_week || 0}
├ Perdidos: ${activity.lost_this_week || 0}
└ Hot Leads activos: ${activity.hot_leads_active || 0}

📨 *MENSAJERIA (7d)*
├ Enviados: ${msgs.msgs_sent_week || 0}
├ Recibidos: ${msgs.msgs_received_week || 0}
├ Respondedores únicos: ${msgs.unique_responders || 0}
└ Errores: ${msgs.errors_week || 0}

🎯 *KPIs*
├ Conversion Rate: ${kpis.conversion_rate || 0}%
├ Engagement Rate: ${kpis.engagement_rate || 0}%
├ Avg AI Score: ${kpis.avg_ai_score || 'N/A'}
└ Avg Follow-ups to Win: ${kpis.avg_followups_to_win || 'N/A'}`;

return [{ json: { report, ...funnel, ...activity, ...msgs, ...kpis } }];
